section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/bug-report-quality-rubric.json",
  "type": "object",
  "required": ["artefact_id", "ticket_ref", "verdict", "score", "dimensions", "version", "last_reviewed"],
  "properties": {
    "artefact_id": {"type": "string", "pattern": "^brq-[a-z0-9-]{6,}$"},
    "ticket_ref":  {"type": "string", "description": "URL or short id of the source ticket"},
    "verdict":     {"enum": ["accept", "block-need-repro", "block-need-evidence", "block-need-ai-context", "block-need-env"]},
    "score":       {"type": "integer", "minimum": 0, "maximum": 100},
    "dimensions": {
      "type": "object",
      "required": ["title", "repro", "expected_vs_actual", "environment", "severity", "priority", "evidence"],
      "properties": {
        "title":              {"type": "integer", "minimum": 0, "maximum": 10},
        "repro":              {"type": "integer", "minimum": 0, "maximum": 20},
        "expected_vs_actual": {"type": "integer", "minimum": 0, "maximum": 15},
        "environment":        {"type": "integer", "minimum": 0, "maximum": 15},
        "severity":           {"type": "integer", "minimum": 0, "maximum": 10},
        "priority":           {"type": "integer", "minimum": 0, "maximum": 10},
        "evidence":           {"type": "integer", "minimum": 0, "maximum": 10},
        "ai_context":         {"type": "integer", "minimum": 0, "maximum": 10}
      }
    },
    "field_fixes": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["field", "issue", "suggested_fix"],
        "properties": {
          "field":         {"type": "string"},
          "issue":         {"type": "string"},
          "suggested_fix": {"type": "string"}
        }
      }
    },
    "is_ai_feature": {"type": "boolean"},
    "version":       {"type": "string", "pattern": "^\\d+\\.\\d+\\.\\d+$"},
    "last_reviewed": {"type": "string", "format": "date"}
  }
}
